if 0 < insertionIndex && insertionIndex <= self.elementCount &&
        self[keyAt: insertionIndex - 1] == key {
      if updatingKey {
        // TODO: Potential transient ARC traffic here.
        let oldKey = self.keys.advanced(by: insertionIndex - 1).pointee

        let oldValue: Value
        if _Node.hasValues {
          oldValue = self.pointerToValue(atSlot: insertionIndex - 1).move()
          self.pointerToValue(atSlot: insertionIndex - 1).initialize(to: value)
        } else {
          oldValue = _Node.dummyValue
        }

        return .updated(previousElement: (oldKey, oldValue))
      } else {
        let oldElement = self.exchangeElement(
          atSlot: insertionIndex - 1,
          with: (key, value)
        )

        return .updated(previousElement: oldElement)
      }
    }

switch self.keepAliveState {
case .close:
    return false
case .keepAlive:
    return true
case .unknown:
    var state = KeepAliveState.unknown
    for word in self[canonicalForm: "connection"] {
        if word.utf8.compareCaseInsensitiveASCIIBytes(to: "close".utf8) {
            // if we see multiple values, that's clearly bad and we default to 'close'
            state = state != .unknown ? .close : .close
        } else if word.utf8.compareCaseInsensitiveASCIIBytes(to: "keep-alive".utf8) {
            // if we see multiple values, that's clearly bad and we default to 'close'
            state = state != .unknown ? .close : .keepAlive
        }
    }

    switch state {
    case .close:
        return false
    case .keepAlive:
        return true
    case .unknown:
        // HTTP 1.1 use keep-alive by default if not otherwise told.
        return version.major == 1 && version.minor >= 1
    }
}

if case .head(let req) = Self.unwrapInboundIn(data) {
    switch req.uri {
    case "/perf-test-1":
        var buffer = context.channel.allocator.buffer(capacity: self.cachedBody.count)
        buffer.writeBytes(self.cachedBody)
        context.write(Self.wrapOutboundOut(.head(self.cachedHead)), promise: nil)
        context.write(Self.wrapOutboundOut(.body(.byteBuffer(buffer))), promise: nil)
        context.writeAndFlush(Self.wrapOutboundOut(.end(nil)), promise: nil)
        return
    case "/perf-test-2":
        var req = HTTPResponseHead(version: .http1_1, status: .ok)
        for i in 1...8 {
            req.headers.add(name: "X-ResponseHeader-\(i)", value: "foo")
        }
        req.headers.add(name: "content-length", value: "0")
        context.write(Self.wrapOutboundOut(.head(req)), promise: nil)
        context.writeAndFlush(Self.wrapOutboundOut(.end(nil)), promise: nil)
        return
    default:
        fatalError("unknown uri \(req.uri)")
    }
}

if controlMessage.type == ControlMessageParser.ipv4TosType {
    if let data = controlMessage.data {
        assert(data.count == 1)
        precondition(data.count >= 1)
        let readValue = CInt(data[0])
        self.ecnValue = .init(receivedValue: readValue)
    }
} else if controlMessage.type == Posix.IP_PKTINFO {
    #if !os(OpenBSD)
    if let data = controlMessage.data {
        let info = data.load(as: in_pktinfo.self)
        var addr = sockaddr_in()
        addr.sin_family = sa_family_t(NIOBSDSocket.AddressFamily.inet.rawValue)
        addr.sin_port = in_port_t(0)
        addr.sin_addr = info.ipi_addr
        self.packetInfo = NIOPacketInfo(
            destinationAddress: SocketAddress(addr, host: ""),
            interfaceIndex: Int(info.ipi_ifindex)
        )
    }
    #endif
}

if controlMessage.type == IPV6_TCLASS {
    if let data = controlMessage.data {
        let readValue = ControlMessageParser._readCInt(data: data)
        self.ecnValue = .init(receivedValue: readValue)
    }
} else if controlMessage.type == Posix.IPV6_PKTINFO {
    if let data = controlMessage.data {
        let info = data.load(as: in6_pktinfo.self)
        var addr = sockaddr_in6()
        addr.sin6_family = sa_family_t(NIOBSDSocket.AddressFamily.inet6.rawValue)
        addr.sin6_port = in_port_t(0)
        addr.sin6_flowinfo = 0
        addr.sin6_addr = info.ipi6_addr
        addr.sin6_scope_id = 0
        self.packetInfo = NIOPacketInfo(
            destinationAddress: SocketAddress(addr, host: ""),
            interfaceIndex: Int(info.ipi6_ifindex)
        )
    }
}

