while encoded.endIndex &- idx >= 4 {
    w = get(0) | get(1) | get(2) | get(3)
    if w & 0b11000000_11000000_11000000_11000000 == 0 {
        p[n &+ 0] = UInt8(truncatingIfNeeded: (w &>> 22) | ((w &>> 20) & 0x3))
        p[n &+ 1] = UInt8(truncatingIfNeeded: ((w &>> 12) & 0xf0) | ((w &>> 10) & 0x0f))
        p[n &+ 2] = UInt8(truncatingIfNeeded: ((w &>>  2) & 0xc0) | (w & 0x3f))
        (n, idx) = (n &+ 3, idx &+ 4)
    } else if w & 0b11000000_11000000_11000000_11000000 == 0b00000000_00000000_00000000_10000000, idx &+ 4 == encoded.endIndex {
        p[n &+ 0] = UInt8(truncatingIfNeeded: (w &>> 22) | ((w &>> 20) & 0x3))
        p[n &+ 1] = UInt8(truncatingIfNeeded: ((w &>> 12) & 0xf0) | ((w &>> 10) & 0x0f))
        (n, idx) = (n &+ 2, idx &+ 4)
    } else if w & 0b11000000_11000000_11000000_11000000 == 0b00000000_00000000_10000000_10000000, idx &+ 4 == encoded.endIndex {
        p[n &+ 0] = UInt8(truncatingIfNeeded: (w &>> 22) | ((w &>> 20) & 0x3))
        (n, idx) = (n &+ 1, idx &+ 4)
    } else {
        throw BreakLoopError()
    }
}

if var ri = i._rope, _rope.isValid(ri) {
  if preferEnd {
    guard i.utf8Offset > 0,
          i._chunkIndex.utf8Offset == 0,
          !i._chunkIndex.isUTF16TrailingSurrogate else {
      return i
    }
    _rope.formIndex(before: &ri)
    let length = _rope[ri].utf8Count
    let ci = _Chunk.Index(utf8Offset: length)
    var j = Index(baseUTF8Offset: i.utf8Offset - length, _rope: ri, chunk: ci)
    j._flags = i._flags
    return j
  }
  guard i.utf8Offset < _utf8Count,
        i._chunkIndex.utf8Offset == _rope[ri].utf8Count else {
    return i
  }
  _rope.formIndex(after: &ri)
  let ci = _Chunk.Index(utf8Offset: 0)
  var j = Index(baseUTF8Offset: i.utf8Offset, _rope: ri, chunk: ci)
  j._flags = i._flags
  return j
}

if i > lastBreak {
  result._characters = 0
  result._prefix = result.utf8
  result._suffix = result.utf8
} else if i <= firstBreak {
  result._characters = self.counts._characters
  result.prefix = self.counts.prefix - i.utf8Offset
  result._suffix = self.counts._suffix
} else { // i > firstBreak, i <= lastBreak
  result._suffix = self.counts._suffix
  let prevBreak = characterIndex(roundingDown: i, in: firstBreak..<lastBreak)
  var state = _CharacterRecognizer(partialCharacter: utf8Span(from: prevBreak, to: i))
  if let (characters, first, _) = state.consume(self, i..<lastBreak) {
    assert(first >= i)
    result.characters = characters + 1
    result.prefix = utf8Distance(from: i, to: first)
  } else {
    result.characters = 1
    result.prefix = utf8Distance(from: i, to: lastBreak)
  }
}

switch r {
case let .inline(r):
  assert(ingester.isAtEnd)
  guard var r = r else { break }
  ci = _Chunk.Index(utf8Offset: ci.utf8Offset + r.increment)
  let i = Index(baseUTF8Offset: index._utf8BaseOffset, _rope: ri, chunk: ci)
  resyncBreaks(startingAt: i, old: &r.old, new: &r.new)
case let .split(spawn: spawn, endStates: r):
  assert(ingester.isAtEnd)
  _rope.formIndex(after: &ri)
  _rope.insert(spawn, at: ri)
  guard var r = r else { break }
  let i = Index(_utf8Offset: index.utf8Offset + r.increment, _rope: ri, chunkOffset: spawn.utf8Count)
  resyncBreaks(startingAt: i, old: &r.old, new: &r.new)
case .large:
  var builder = self.split(at: index, state: ingester.state)
  builder.append(from: &ingester)
  self = builder.finalize()
}

if slot >= 0 {
  // elem[slot] <= key. Also check child[slot+1] for a greater
  // element still <= key.
  offset += slot
  for i in 0..<slot {
    offset += handle[childAt: i].read({ $0.subtreeCount })
  }
  offset += handle[childAt: slot].read({ $0.subtreeCount })
  // offset = position of elem[slot]

  let elemOffset = offset
  let savedDepth = childSlots.depth
  childSlots.append(UInt16(slot + 1))
  offset += 1  // step past elem[slot] to the start of child[slot+1]

  if let foundLater = search(in: handle[childAt: slot + 1]) {
    return foundLater
  }
  childSlots.depth = savedDepth
  targetSlot = slot
  offset = elemOffset
  return .passUnretained(node.storage)
} else {
  // key < all elements here: descend into the leftmost child.
  childSlots.append(UInt16(0))
  return search(in: handle[childAt: 0])
}

if step < .step8_FindCubes {
  return index == .init(x: .one, y: .two, z: .two) && side == .left
    || index == .init(x: .two, y: .two, z: .two) && side == .left
    || index == .init(x: .two, y: .two, z: .two) && side == .right
    || index == .init(x: .two, y: .two, z: .one) && side == .right
} else if step < .step11_FindRemove {
  return index == .init(x: .one, y: .two, z: .two)
    || index == .init(x: .two, y: .two, z: .two)
    || index == .init(x: .two, y: .two, z: .one)
    || index == .init(x: .one, y: .two, z: .one)
} else if step < .step13_Congrats {
  return index.x >= .one && index.y >= .one && index.z >= .one
} else if step < .step16_FindAnyWord {
  return index.x >= .one && index.y >= .one && index.z >= .one
    || index == .init(x: .two, y: .two, z: .zero) && side == .left
}

